use regex::Regex;

fn main() {
    let re = Regex::new(r"\b(\w+)@(\w+\.\w+)\b").unwrap();
    let text = "Contact alice@example.com or bob@rust-lang.org";

    // Check if pattern matches
    println!("Has email: {}", re.is_match(text));

    // Find all matches
    for cap in re.captures_iter(text) {
        println!("Full: {}, User: {}, Domain: {}",
            &cap[0], &cap[1], &cap[2]);
    }

    // Replace matches
    let redacted = re.replace_all(text, "[REDACTED]");
    println!("Redacted: {}", redacted);
}

